+const CUSTOM_EXPECTED_ONE_OF_RE = /expected one of ((?:"[^"]+"(?:\|"?[^"]+"?)*)+)/i;
+const STREAMING_ALLOWED_VALUES = [true, false, "off", "partial", "block", "progress"] as const;
